1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
4	type QuoteResult = { premium: number };
5	
6	const PROCESSING_FEE = 5;
7	const FIRST_INSURANCE_SURCHARGE = 0.1;
8	const CURSE_SURCHARGE = 0.5;
9	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
10	const HIGH_ENCHANTMENT_THRESHOLD = 5;
11	
12	const BASE_PREMIUM: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	const BLOCK_SIZE = 3;
23	const BLOCK_PREMIUM = 60;
24	
25	const isBlock = (type: string, count: number): boolean =>
26	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
27	
28	const groupPremium = (type: string, count: number): number =>
29	  isBlock(type, count) ? BLOCK_PREMIUM : BASE_PREMIUM[type] * count;
30	
31	const countByType = (items: Item[]): Map<string, number> => {
32	  const counts = new Map<string, number>();
33	  for (const { type } of items) counts.set(type, (counts.get(type) ?? 0) + 1);
34	  return counts;
35	};
36	
37	const basePremiumForItems = (items: Item[]): number =>
38	  [...countByType(items)].reduce(
39	    (total, [type, count]) => total + groupPremium(type, count),
40	    0,
41	  );
42	
43	const perItemSurcharge = (
44	  items: Item[],
45	  applies: (item: Item) => boolean,
46	  rate: number,
47	): number =>
48	  items.reduce(
49	    (total, item) => total + (applies(item) ? BASE_PREMIUM[item.type] * rate : 0),
50	    0,
51	  );
52	
53	const isCursed = (item: Item): boolean => item.cursed === true;
54	const isHighlyEnchanted = (item: Item): boolean =>
55	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
56	
57	const withFirstInsuranceSurcharge = (amount: number): number =>
58	  amount + amount * FIRST_INSURANCE_SURCHARGE;
59	
60	const itemizedPremium = (items: Item[]): number =>
61	  basePremiumForItems(items)
62	  + perItemSurcharge(items, isCursed, CURSE_SURCHARGE)
63	  + perItemSurcharge(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE);
64	
65	const quotePremium = ({ items }: QuoteStep): QuoteResult => {
66	  const perItemSubtotal = itemizedPremium(items);
67	  const afterFirstInsurance = withFirstInsuranceSurcharge(perItemSubtotal);
68	  const totalBeforeRounding = afterFirstInsurance + PROCESSING_FEE;
69	  return { premium: Math.ceil(totalBeforeRounding) };
70	};
71	
72	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => ({
73	  results: scenario.steps.map(quotePremium),
74	});
